import { NextRequest, NextResponse } from "next/server";
import { getStripe } from "@/lib/stripe";
import { STRIPE_PRICE_ID } from "@/lib/config";

/**
 * Creates a Stripe Customer + Subscription with `payment_behavior: default_incomplete`.
 * Returns the PaymentIntent clientSecret so the frontend can mount <PaymentElement>
 * inside our custom NYT-style modal (Apple/Google Pay render automatically).
 *
 * Demo mode: returns { demo: true } — frontend renders a fake form instead.
 */
export async function POST(req: NextRequest) {
  const stripe = getStripe();

  if (!stripe || !STRIPE_PRICE_ID) {
    return NextResponse.json({ demo: true });
  }

  const { walletAddress, email } = await req.json();

  const customer = await stripe.customers.create({
    email: email || undefined,
    metadata: { walletAddress: walletAddress || "" },
  });

  const subscription = await stripe.subscriptions.create({
    customer: customer.id,
    items: [{ price: STRIPE_PRICE_ID }],
    payment_behavior: "default_incomplete",
    payment_settings: {
      save_default_payment_method: "on_subscription",
      payment_method_types: ["card"], // Apple/Google Pay surface via card
    },
    expand: ["latest_invoice.payment_intent"],
    metadata: { walletAddress: walletAddress || "" },
  });

  const invoice = subscription.latest_invoice;
  if (!invoice || typeof invoice === "string") {
    return NextResponse.json({ error: "No invoice" }, { status: 500 });
  }
  const pi = invoice.payment_intent;
  if (!pi || typeof pi === "string") {
    return NextResponse.json({ error: "No payment intent" }, { status: 500 });
  }

  return NextResponse.json({
    clientSecret: pi.client_secret,
    subscriptionId: subscription.id,
  });
}

import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { getStripe } from "@/lib/stripe";

/**
 * Stripe webhook handler.
 *
 * invoice.paid           → mint MembershipPass NFT to walletAddress (subscription metadata)
 * customer.subscription.deleted → revoke NFT
 *
 * Minting is stubbed until THIRDWEB_SECRET_KEY + contract address are set.
 * To wire up: use thirdweb's Engine or `sendTransaction` with a backend wallet
 * to call MembershipPass.mint(walletAddress).
 */
export async function POST(req: NextRequest) {
  const stripe = getStripe();
  const secret = process.env.STRIPE_WEBHOOK_SECRET;

  if (!stripe || !secret) {
    return NextResponse.json({ received: true, demo: true });
  }

  const body = await req.text();
  const sig = req.headers.get("stripe-signature");
  if (!sig) {
    return NextResponse.json({ error: "No signature" }, { status: 400 });
  }

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(body, sig, secret);
  } catch (err) {
    const msg = err instanceof Error ? err.message : "Invalid signature";
    return NextResponse.json({ error: msg }, { status: 400 });
  }

  switch (event.type) {
    case "invoice.paid": {
      const invoice = event.data.object as Stripe.Invoice;
      const subId = invoice.subscription;
      if (subId && typeof subId === "string") {
        const sub = await stripe.subscriptions.retrieve(subId);
        const wallet = sub.metadata.walletAddress;
        if (wallet) {
          // TODO: mint MembershipPass NFT to `wallet` via ThirdWeb
          console.log(`[webhook] would mint NFT to ${wallet}`);
        }
      }
      break;
    }
    case "customer.subscription.deleted": {
      const sub = event.data.object as Stripe.Subscription;
      const wallet = sub.metadata.walletAddress;
      if (wallet) {
        // TODO: call MembershipPass.revoke(wallet)
        console.log(`[webhook] would revoke NFT from ${wallet}`);
      }
      break;
    }
  }

  return NextResponse.json({ received: true });
}

import { NextResponse } from "next/server";
import { getMux } from "@/lib/mux";

/**
 * Creates a Mux direct-upload URL. <MuxUploader> on /uploads calls this
 * via its `endpoint` prop and uploads the file directly to Mux.
 *
 * Demo mode: returns { demo: true } — uploads page falls back to a
 * placeholder file input that does nothing.
 */
export async function POST() {
  const mux = getMux();

  if (!mux) {
    return NextResponse.json({ demo: true });
  }

  const upload = await mux.video.uploads.create({
    new_asset_settings: {
      playback_policy: ["public"],
      encoding_tier: "baseline",
    },
    cors_origin: "*",
  });

  return NextResponse.json({
    url: upload.url,
    uploadId: upload.id,
  });
}

