"use client";

import { ThirdwebProvider } from "thirdweb/react";
import { ReactNode } from "react";

export function Providers({ children }: { children: ReactNode }) {
  return <ThirdwebProvider>{children}</ThirdwebProvider>;
}

"use client";

import {
  createContext,
  useContext,
  useState,
  useEffect,
  ReactNode,
} from "react";

/**
 * Tracks membership + demo-wallet state in localStorage so the demo
 * survives page reloads. When real ThirdWeb/Stripe keys are set,
 * `isMember` should instead be derived from on-chain `balanceOf`.
 */

interface MembershipState {
  isSignedIn: boolean;
  isMember: boolean;
  demoWallet: string | null;
  signInDemo: () => void;
  signOutDemo: () => void;
  grantMembership: () => void;
}

const Ctx = createContext<MembershipState | null>(null);

const LS_WALLET = "demo:wallet";
const LS_MEMBER = "demo:membership";

export function MembershipProvider({ children }: { children: ReactNode }) {
  const [demoWallet, setDemoWallet] = useState<string | null>(null);
  const [isMember, setIsMember] = useState(false);

  useEffect(() => {
    setDemoWallet(localStorage.getItem(LS_WALLET));
    setIsMember(localStorage.getItem(LS_MEMBER) === "true");
  }, []);

  const signInDemo = () => {
    const addr = "0xDEMO" + Math.random().toString(16).slice(2, 10);
    localStorage.setItem(LS_WALLET, addr);
    setDemoWallet(addr);
  };

  const signOutDemo = () => {
    localStorage.removeItem(LS_WALLET);
    localStorage.removeItem(LS_MEMBER);
    setDemoWallet(null);
    setIsMember(false);
  };

  const grantMembership = () => {
    localStorage.setItem(LS_MEMBER, "true");
    setIsMember(true);
  };

  return (
    <Ctx.Provider
      value={{
        isSignedIn: !!demoWallet,
        isMember,
        demoWallet,
        signInDemo,
        signOutDemo,
        grantMembership,
      }}
    >
      {children}
    </Ctx.Provider>
  );
}

export function useMembership() {
  const ctx = useContext(Ctx);
  if (!ctx) throw new Error("useMembership must be used within MembershipProvider");
  return ctx;
}

"use client";

import { ConnectButton, useActiveAccount } from "thirdweb/react";
import { inAppWallet, createWallet } from "thirdweb/wallets";
import { thirdwebClient, chain } from "@/lib/thirdweb";
import { clientDemo } from "@/lib/config";
import { useMembership } from "./MembershipContext";

/**
 * Top-right sign-in. When NEXT_PUBLIC_THIRDWEB_CLIENT_ID is set, renders
 * ThirdWeb's ConnectButton with social login (Google/Apple/Email embedded
 * wallet). In demo mode, a simple localStorage-backed button.
 */

const wallets = [
  inAppWallet({
    auth: { options: ["google", "apple", "email", "passkey"] },
  }),
  createWallet("io.metamask"),
  createWallet("com.coinbase.wallet"),
];

export function ConnectWallet() {
  const { isSignedIn, demoWallet, signInDemo, signOutDemo } = useMembership();
  const account = useActiveAccount();

  // Real ThirdWeb mode
  if (!clientDemo.thirdweb && thirdwebClient) {
    return (
      <ConnectButton
        client={thirdwebClient}
        wallets={wallets}
        chain={chain}
        connectButton={{
          label: "Sign In",
          className: "!font-title !font-bold",
        }}
        connectModal={{
          title: "Sign in to continue",
          titleIcon: "",
          size: "compact",
        }}
        theme="light"
      />
    );
  }

  // Demo fallback
  if (isSignedIn || account) {
    const display = account?.address || demoWallet || "";
    return (
      <button
        onClick={signOutDemo}
        className="font-body text-sm px-4 py-2 rounded-full bg-zinc-100 hover:bg-zinc-200 transition"
        title="Click to sign out"
      >
        {display.slice(0, 6)}…{display.slice(-4)}
      </button>
    );
  }

  return (
    <button
      onClick={signInDemo}
      className="font-title font-bold text-sm px-5 py-2 rounded-full bg-black text-white hover:bg-zinc-800 transition"
    >
      Sign In
    </button>
  );
}

