     4→import {ERC721} from "@openzeppelin/contracts/token/ERC721/ERC721.sol";
     5→import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
     6→
     7→/**
     8→ * @title MembershipPass
     9→ * @notice ERC-721 membership token. One pass per address, minted by the
    10→ *         backend when a Stripe subscription's first invoice is paid,
    11→ *         and revoked (burned) when the subscription is canceled.
    12→ *
    13→ * @dev Deploy via ThirdWeb dashboard or `npx thirdweb deploy`.
    14→ *      The deployer becomes the owner; transfer ownership to your backend
    15→ *      signer wallet so the Stripe webhook can call mint/revoke.
    16→ *
    17→ *      Frontend access check:
    18→ *        balanceOf(user) > 0  →  has access
    19→ *
    20→ *      Backend (in webhook):
    21→ *        contract.mint(walletAddress)   // on invoice.paid
    22→ *        contract.revoke(walletAddress) // on subscription.deleted
    23→ */
    24→contract MembershipPass is ERC721, Ownable {
    25→    uint256 private _nextTokenId;
    26→
    27→    /// @notice Maps a member's address to their token ID (0 = not a member).
    28→    mapping(address => uint256) public memberToken;
    29→
    30→    event Minted(address indexed to, uint256 indexed tokenId);
    31→    event Revoked(address indexed from, uint256 indexed tokenId);
    32→
    33→    constructor(
    34→        address initialOwner
    35→    ) ERC721("Membership Pass", "PASS") Ownable(initialOwner) {}
    36→
    37→    /**
    38→     * @notice Mint a membership pass to `to`. Reverts if already a member.
    39→     * @dev Only callable by owner (your backend signer).
    40→     */
    41→    function mint(address to) external onlyOwner returns (uint256) {
    42→        require(memberToken[to] == 0, "MembershipPass: already a member");
    43→        uint256 tokenId = ++_nextTokenId;
    44→        memberToken[to] = tokenId;
    45→        _safeMint(to, tokenId);
    46→        emit Minted(to, tokenId);
    47→        return tokenId;
    48→    }
    49→
    50→    /**
    51→     * @notice Burn `member`'s pass. Called when their subscription is canceled.
    52→     * @dev Only callable by owner.
    53→     */
    54→    function revoke(address member) external onlyOwner {
    55→        uint256 tokenId = memberToken[member];
    56→        require(tokenId != 0, "MembershipPass: not a member");
    57→        delete memberToken[member];
    58→        _burn(tokenId);
    59→        emit Revoked(member, tokenId);
    60→    }
    61→
    62→    /// @notice Convenience view for the frontend.
    63→    function isMember(address account) external view returns (bool) {
    64→        return memberToken[account] != 0;
    65→    }
    66→
    67→    // ─────────────────────────────────────────────────────────────────────
    68→    // SOULBOUND OPTION
    69→    // Uncomment to make passes non-transferable. Members can't sell or move
    70→    // their pass — only the owner can mint or burn. Recommended if access
    71→    // should be strictly tied to the paying account.
    72→    // ─────────────────────────────────────────────────────────────────────
    73→    //
