import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { getStripe } from "@/lib/stripe";

/**
 * Stripe webhook handler.
 *
 * invoice.paid           → mint MembershipPass NFT to walletAddress (subscription metadata)
 * customer.subscription.deleted → revoke NFT
 *
 * Minting is stubbed until THIRDWEB_SECRET_KEY + contract address are set.
 * To wire up: use thirdweb's Engine or `sendTransaction` with a backend wallet
 * to call MembershipPass.mint(walletAddress).
 */
export async function POST(req: NextRequest) {
  const stripe = getStripe();
